import { serve } from "https://deno.land/std@0.190.0/http/server.ts";

const DEFAULT_MODULES = [
  "https://deno.land/std@0.190.0/uuid/mod.ts",
  "https://deno.land/std@0.190.0/path/mod.ts",
];

async function handler(req: Request): Promise<Response> {
  const url = new URL(req.url);

  // 1. Get module paths from query parameters
  const queryModules = url.searchParams.getAll("module");

  // 2. Get module paths from environment variables
  const envModulesString = Deno.env.get("DENO_DEPLOY_MODULES");
  const envModules = envModulesString ? envModulesString.split(",") : [];

  // Combine and deduplicate module paths
  const allModulePaths = Array.from(new Set([
    ...DEFAULT_MODULES,
    ...queryModules,
    ...envModules,
  ]));

  const loadedModules: { [key: string]: unknown } = {};
  const errors: { [key: string]: string } = {};

  for (const path of allModulePaths) {
    try {
      // Dynamic import the module
      const module = await import(path);
      loadedModules[path] = module;
    } catch (e) {
      console.error(`Failed to load module ${path}:`, e);
      errors[path] = e.message;
    }
  }

  // Example of using a loaded module (if uuid was loaded)
  let exampleUsage = "No uuid module loaded or example not implemented.";
  if (loadedModules["https://deno.land/std@0.190.0/uuid/mod.ts"]) {
    try {
      const uuidModule = loadedModules["https://deno.land/std@0.190.0/uuid/mod.ts"] as typeof import("https://deno.land/std@0.190.0/uuid/mod.ts");
      exampleUsage = `Generated UUID: ${uuidModule.v4.generate()}`;
    } catch (e) {
      exampleUsage = `Error using uuid module: ${e.message}`;
    }
  }

  const responseBody = {
    message: "Modules loaded dynamically!",
    loadedModulePaths: Object.keys(loadedModules),
    failedModulePaths: Object.keys(errors),
    errors,
    exampleUsage,
    allModulePathsConsidered: allModulePaths,
  };

  return new Response(JSON.stringify(responseBody, null, 2), {
    headers: { "Content-Type": "application/json" },
  });
}

